sql:
SELECT court_name
FROM facility_courts
WHERE is_indoor = 1;

SELECT AVG(temperature) AS average_temperature
FROM historical_data
WHERE play_decision = 'Yes';

SELECT AVG(temperature_value) AS average_temperature
FROM weather_conditions
WHERE wind_speed > 15 AND temperature_value > 25;

external_knowledge:
External knowledge:
- A 'play decision' refers to the decision of whether or not to play tennis based on the weather conditions;
- The 'latest overall weather condition' is determined by the most recent weather data and sensor readings;
- The 'current weather outlook' includes attributes such as temperature, humidity, wind strength, and precipitation.

sql:
SELECT date_recorded, play_decision
FROM historical_data
ORDER BY date_recorded DESC;
